import{_ as a,o as t,c as n,ae as r}from"./chunks/framework.WV23YX7-.js";const i="/all-time-wrestling-rpg/screenshots/admin-season-settings-confirmation.png",s="/all-time-wrestling-rpg/screenshots/admin-wrestler-relationships.png",o="/all-time-wrestling-rpg/screenshots/admin-show-template-art-generation.png",l="/all-time-wrestling-rpg/screenshots/admin-season-settings-before-generation.png",m="/all-time-wrestling-rpg/screenshots/admin-observability-performance.png",h="/all-time-wrestling-rpg/screenshots/admin-season-settings-after-generation.png",c="/all-time-wrestling-rpg/screenshots/admin-observability-cache.png",d="/all-time-wrestling-rpg/screenshots/admin-observability-database.png",p="/all-time-wrestling-rpg/screenshots/admin-observability-pulse.png",g="/all-time-wrestling-rpg/screenshots/admin-tools.png",u="/all-time-wrestling-rpg/screenshots/admin-show-templates.png",f="/all-time-wrestling-rpg/screenshots/admin-ai-settings.png",b="/all-time-wrestling-rpg/screenshots/admin-injury-types.png",S="/all-time-wrestling-rpg/screenshots/admin-wrestler-list.png",w="/all-time-wrestling-rpg/screenshots/admin-expansion-management.png",v=JSON.parse('{"title":"Admin","description":"","frontmatter":{},"headers":[],"relativePath":"guide/admin.md","filePath":"guide/admin.md"}'),_={name:"guide/admin.md"};function y(q,e,M,x,P,k){return t(),n("div",null,[...e[0]||(e[0]=[r('<h1 id="admin" tabindex="-1">Admin <a class="header-anchor" href="#admin" aria-label="Permalink to &quot;Admin&quot;">​</a></h1><p>Welcome to the Admin guide. This documentation is automatically generated from the latest game features.</p><h2 id="season-settings-schedule-generation-confirmation" tabindex="-1">Season Settings - Schedule Generation Confirmation <a class="header-anchor" href="#season-settings-schedule-generation-confirmation" aria-label="Permalink to &quot;Season Settings - Schedule Generation Confirmation&quot;">​</a></h2><p>The Season Settings tab showing the &#39;Generate Season Confirmation&#39; button, before execution.</p><p><img src="'+i+'" alt="Season Settings - Schedule Generation Confirmation"></p><hr><h2 id="wrestler-relationships-management" tabindex="-1">Wrestler Relationships Management <a class="header-anchor" href="#wrestler-relationships-management" aria-label="Permalink to &quot;Wrestler Relationships Management&quot;">​</a></h2><p>Manage the social fabric of your promotion. Define marriages, family ties, and deep friendships that influence chemistry, AI narration, and random backstage events.</p><p><img src="'+s+'" alt="Wrestler Relationships Management"></p><hr><h2 id="generate-template-art" tabindex="-1">Generate Template Art <a class="header-anchor" href="#generate-template-art" aria-label="Permalink to &quot;Generate Template Art&quot;">​</a></h2><p>Create unique branding for your show templates using AI. This art will be used in the booking interface and calendar.</p><p><img src="'+o+'" alt="Generate Template Art"></p><hr><h2 id="season-settings-before-schedule-generation" tabindex="-1">Season Settings - Before Schedule Generation <a class="header-anchor" href="#season-settings-before-schedule-generation" aria-label="Permalink to &quot;Season Settings - Before Schedule Generation&quot;">​</a></h2><p>The Season Settings tab showing the &#39;Generate Season Schedule&#39; button, before execution.</p><p><img src="'+l+'" alt="Season Settings - Before Schedule Generation"></p><hr><h2 id="system-performance" tabindex="-1">System Performance <a class="header-anchor" href="#system-performance" aria-label="Permalink to &quot;System Performance&quot;">​</a></h2><p>Monitor AI response times and resource usage.</p><p><img src="'+m+'" alt="System Performance"></p><hr><h2 id="season-settings-after-schedule-generation" tabindex="-1">Season Settings - After Schedule Generation <a class="header-anchor" href="#season-settings-after-schedule-generation" aria-label="Permalink to &quot;Season Settings - After Schedule Generation&quot;">​</a></h2><p>The Season Settings tab after successfully generating the season schedule.</p><p><img src="'+h+'" alt="Season Settings - After Schedule Generation"></p><hr><h2 id="cache-management" tabindex="-1">Cache Management <a class="header-anchor" href="#cache-management" aria-label="Permalink to &quot;Cache Management&quot;">​</a></h2><p>Monitor and manage application caches.</p><p><img src="'+c+'" alt="Cache Management"></p><hr><h2 id="database-management" tabindex="-1">Database Management <a class="header-anchor" href="#database-management" aria-label="Permalink to &quot;Database Management&quot;">​</a></h2><p>Monitor database statistics and optimize performance.</p><p><img src="'+d+'" alt="Database Management"></p><hr><h2 id="system-pulse" tabindex="-1">System Pulse <a class="header-anchor" href="#system-pulse" aria-label="Permalink to &quot;System Pulse&quot;">​</a></h2><p>Real-time health status of the application.</p><p><img src="'+p+'" alt="System Pulse"></p><hr><h2 id="admin-tools" tabindex="-1">Admin Tools <a class="header-anchor" href="#admin-tools" aria-label="Permalink to &quot;Admin Tools&quot;">​</a></h2><p>Perform critical maintenance tasks such as manual tier recalculation and account management.</p><p><img src="'+g+'" alt="Admin Tools"></p><hr><h2 id="show-templates" tabindex="-1">Show Templates <a class="header-anchor" href="#show-templates" aria-label="Permalink to &quot;Show Templates&quot;">​</a></h2><p>Manage templates for your shows. You can define default match and promo counts, and now generate custom AI art for each template.</p><p><img src="'+u+'" alt="Show Templates"></p><hr><h2 id="ai-configuration" tabindex="-1">AI Configuration <a class="header-anchor" href="#ai-configuration" aria-label="Permalink to &quot;AI Configuration&quot;">​</a></h2><p>Configure the Artificial Intelligence providers used for match narration, image generation, and creative assistance. You can switch between different LLM providers (OpenAI, Anthropic, Gemini) and configure their specific settings.</p><p><img src="'+f+'" alt="AI Configuration"></p><hr><h2 id="injury-management" tabindex="-1">Injury Management <a class="header-anchor" href="#injury-management" aria-label="Permalink to &quot;Injury Management&quot;">​</a></h2><p>Define different types of injuries, their severity, and recovery times. These are used to dynamically affect wrestler performance and availability in the campaign and booking modes.</p><p><img src="'+b+'" alt="Injury Management"></p><hr><h2 id="wrestler-management" tabindex="-1">Wrestler Management <a class="header-anchor" href="#wrestler-management" aria-label="Permalink to &quot;Wrestler Management&quot;">​</a></h2><p>Manage the entire roster of wrestlers. Add new talent, edit existing stats, assign images, and manage contract details from this centralized view.</p><p><img src="'+S+'" alt="Wrestler Management"></p><hr><h2 id="expansion-management" tabindex="-1">Expansion Management <a class="header-anchor" href="#expansion-management" aria-label="Permalink to &quot;Expansion Management&quot;">​</a></h2><p>Group and toggle themed content sets. Enable or disable entire collections of wrestlers, teams, and factions to customize the available roster for matches and leagues.</p><p><img src="'+w+'" alt="Expansion Management"></p><hr><h2 id="video-walkthroughs" tabindex="-1">Video Walkthroughs <a class="header-anchor" href="#video-walkthroughs" aria-label="Permalink to &quot;Video Walkthroughs&quot;">​</a></h2><h3 id="mysql-data-migration-wizard" tabindex="-1">MySQL Data Migration Wizard <a class="header-anchor" href="#mysql-data-migration-wizard" aria-label="Permalink to &quot;MySQL Data Migration Wizard&quot;">​</a></h3><p>Migration complete — all data is now in MySQL and verified. Restart the application with the MySQL Spring profile (spring.profiles.active=mysql) to run in production mode against the new database.</p><video controls width="100%" style="border-radius:8px;margin-bottom:1rem;"><source src="https://javydreamercsw.github.io/all-time-wrestling-rpg/videos/data-transfer-full-wizard.mp4" type="video/mp4"></video><hr>',67)])])}const T=a(_,[["render",y]]);export{v as __pageData,T as default};
